transformScript:
let chapters = [];
let page = 1;
loop {
  let result = http("GET", `https://api.reader.example/series/${captures.slug}/chapters?page=${page}`, #{ "Accept": "application/json" }, "");
  if result.status != 200 { throw `HTTP ${result.status}`; }
  for chapter in result.json.chapters { chapters.push(chapter); }
  if !result.json.has_more { break; }
  page += 1;
}
